create extension if not exists pgcrypto;
create table contestants(id uuid primary key default gen_random_uuid(),contestant_number int unique not null,full_name text not null,country text not null,age int check(age between 16 and 80),profile_image text,created_at timestamptz default now());
create table judges(id uuid primary key default gen_random_uuid(),username text unique not null,password_hash text not null,full_name text not null,active_status boolean default true);
create type score_category as enum('Welcome Ceremony','National Costume','Preliminary Swimsuit Competition','Preliminary Evening Gown Competition','Final Swimsuit Competition','Final Evening Gown Competition','Final Question');
create table scores(id uuid primary key default gen_random_uuid(),contestant_id uuid references contestants on delete cascade,judge_id uuid references judges on delete cascade,category score_category not null,score numeric(3,1) not null check(score between 1.0 and 10.0),submitted boolean default false,locked_at timestamptz,created_at timestamptz default now(),updated_at timestamptz default now(),unique(contestant_id,judge_id,category));
create table vote_packages(id uuid primary key default gen_random_uuid(),name text not null,votes int not null,amount_cents int not null,active boolean default true);
create table popular_votes(id uuid primary key default gen_random_uuid(),contestant_id uuid references contestants on delete cascade,email text not null,votes int not null,amount_cents int not null,receipt_id text,ip_hash text,created_at timestamptz default now());
alter table contestants enable row level security;alter table judges enable row level security;alter table scores enable row level security;alter table vote_packages enable row level security;alter table popular_votes enable row level security;
create policy "public contestants" on contestants for select using(true);create policy "public vote packages" on vote_packages for select using(active);create policy "service manages all contestants" on contestants using(auth.role()='service_role') with check(auth.role()='service_role');create policy "service manages judges" on judges using(auth.role()='service_role') with check(auth.role()='service_role');create policy "service manages scores" on scores using(auth.role()='service_role') with check(auth.role()='service_role');create policy "insert popular votes" on popular_votes for insert with check(true);create policy "service reads popular votes" on popular_votes for select using(auth.role()='service_role');
create or replace function prevent_locked_score_update() returns trigger language plpgsql as $$ begin if old.submitted=true and old.locked_at is not null then raise exception 'Score is locked after final submit'; end if; new.updated_at=now(); return new; end $$;create trigger scores_lock before update on scores for each row execute function prevent_locked_score_update();
create index scores_category_idx on scores(category);create index popular_votes_contestant_idx on popular_votes(contestant_id);
